head.script:
/**
 * 화 면 명 : 고정자산대사
 * 메뉴경로 : 회계/재무회계/고정자산/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_303_01_01b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-11-20
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 *    5. footer에 값 처리
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. 엑셀다운로드 시 Number타입 excelFormat, excelCellType 옵션 추가 작업
 *    3. 엑셀다운로드 시 엑셀에 제목추가(downloadGridViewExcel 함수 사용)
 * 수정이력 :
 *    - 2025-11-20      배기원    최초작성
 */
//hidden 값
scwin.txtCoCd     = "";         //회사코드(hidden, ASIS 사용안함)
scwin.txtCoClsCd  = "";         //회사구분코드(hidden, 회사팝업호출 시)

scwin.pos_groupCode = 0;        //ASIS 사용안함
scwin.getFinalCloseYearMonth;   //ASIS 사용안함

//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

scwin.today = "";       //오늘날짜(엑셀다운로드시 사용)

scwin.initJson = {};    //초기세팅값(TOBE)
scwin.first = 0;

scwin.msg2 = false;
scwin.msg3 = false;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    // $c.gus.cfDisableKey();
    // scwin.f_createHeader1();
    // scwin.f_createHeader2();
    // scwin.f_createHeader3();

    // ds_asetPattern.DataId = "/ac.fi.fixedaset.RetreiveFixedAsetPatternListCMD.do?useYn=1&asetPatternClsCd=1"

    // ds_asetPattern.undoAll();

    // gr_fixedAssetList1.headerHeight = 30;
    // gr_fixedAssetList2.headerHeight = 30;
    // gr_fixedAssetList3.headerHeight = 30;

    // scwin.f_setCompanyInfo();

    // scwin.f_Setting();

    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;
    /**
     * TODO : 임시로 회사코드 초기값 가지고 있기 위해 처리
     * 로드 시 마지막으로 처리되는 로직
     */
    const codeOptions = [
        { grpCd: "EQ055", compID: "" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    scwin.initJson = dma_search1.getJSON();
};


/**
 * 자산유형 조회
 */
scwin.f_asetPattern = function() {
    ds_asetPattern.removeAll();
    $c.sbm.execute(sbm_asetPattern, {"useYn":"1"});
    ds_asetPattern.sort("asetPatternCd", 0);
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_fixedAssetList1.setNoResultMessageVisible(false);
    gr_fixedAssetList2.setNoResultMessageVisible(false);
    gr_fixedAssetList3.setNoResultMessageVisible(false);
    ds_fixedAssetList1.removeAll();
    ds_fixedAssetList2.removeAll();
    ds_fixedAssetList3.removeAll();
    totalRows1.setValue("0");
    totalRows2.setValue("0");
    totalRows3.setValue("0");
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.f_asetPattern();
    scwin.setInit();
    scwin.f_setCompanyInfo();
    scwin.f_Setting();
};

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ed_coCd, ed_coNm]);
    dma_search1.setJSON(scwin.initJson);
    scwin.f_Setting();
    ed_coCd.hidVal       = "";      //회사코드(조회)
    ed_acctDeptCd.hidVal = "";      //귀속부서코드(조회)
};


/**
 * 마감년월 가져오기
 */
scwin.f_getFinalCloseYearMonth = async function () {
    var currentYearMonth = ica_closeYm.getValue();
    // SELECT 절
    var param1 = " NVL(TO_CHAR(ADD_MONTHS(TO_DATE(MIN(CLOSE_YM), 'YYYYMM'), -1), 'YYYYMM'), TO_CHAR(TO_NUMBER(SUBSTR ('" + currentYearMonth + "', 1, 6))-1)) as COL1 "
        + ",'' as COL2 "
        + ",'' as COL3 "
        + ",'' as COL4 "
        + ",'' as COL5 "
        + ",'' as COL6 "
        + ",'' as COL7 "
        + ",'' as COL8 "
        + ",'' as COL9 "
        + ",'' as COL10"
        ;

    // 대상테이블
    var param2 = " TB_ZZ419 ";

    // 조건절
    var param3 =
        " AND CLOSE_YM < SUBSTR ('" + currentYearMonth + "', 1, 6)"
        + " AND WRK_NO = 'FI01'"
        + " AND CLOSE_PRGS_STS_CD ='1'"
        + " AND CO_CD = " + ica_closeYm.getValue()
        ;

    // 정렬
    var param4 =
        " COL1 "
        ;

    // ds_test.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1
    //     + "&param2=" + param2
    //     + "&param3=" + param3
    //     + "&param4=" + param4;
    // ds_test.undoAll();

    ds_test.removeAll();
    dma_test.setEmptyValue();
    dma_test.set("sysCd", "CommonEBC");
    dma_test.set("queryId", "dinymicQueryTest");
    dma_test.set("param1", param1);
    dma_test.set("param2", param2);
    dma_test.set("param3", param3);
    dma_test.set("param4", param4);

    let ret = await $c.sbm.execute(sbm_retrieveCommonPopup);
    ds_test.setJSON(ret.responseJSON.GAUCE);
};


