/**
 * 화면셋팅
 */
scwin.f_Setting = function() {
    ed_acctDeptCd.setValue("00000");
    ed_acctDeptNm.setValue("전사");

    lc_asetPatternCd.setValue("");
    // lc_code.setValue("0");

    scwin.today   = $c.date.getServerDateTime();
    let closeYm   = scwin.today.substring(0,6);
    let lastDD    = $c.date.getLastDateOfMonth(closeYm);

    ica_closeYm.setValue(closeYm);
    ica_fromDate1.setValue(closeYm+"01");
    ica_fromDate2.setValue(closeYm+"01");

    ica_toDate1.setValue(closeYm+lastDD);
    ica_toDate2.setValue(closeYm+lastDD);
};


/**
 * 자회사 회계 시스템 추가에 따른 설정 
 */
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};

/**
 * 회사코드 초기화
 */
scwin.f_initObj = function() {
    $c.gus.cfInitObjects([ed_coCd, ed_coNm]);
};

