/**
 * 회사코드 팝업 callBack
 */
scwin.udc_comCode_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        if(ed_coCd.hidVal != ret[0] ) {
            scwin.f_initObj();
        }

        ed_coCd.setValue(ret[0]);        // 코드
        ed_coNm.setValue(ret[5]);        // 회사명
        ed_coCd.hidVal = ret[0];         // 히든값
        scwin.txtCoClsCd = ret[1];       // 회사구분
    } else {
        ed_coCd.setValue("");            // 코드
        ed_coNm.setValue("");            // 회사명
        ed_coCd.hidVal   = "";           // 히든값
        scwin.txtCoClsCd = "";           // 회사구분
    }

    //TODO : 처음 로딩 시 한번만 처리(웹스퀘어 UDC 싱크....)
    if(scwin.first == 0) {
		// 자회사 회계 시스템
        if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
            scwin.isSubCompany = true;
        } else {
            scwin.isSubCompany = false;
        }
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }
    scwin.first++;
};


/**
 * 조회1
 */
scwin.f_Retrieve1 = async function () {
    let ret;
    ret = await $c.gus.cfValidate([ed_coCd, ed_coNm, ica_closeYm, ed_acctDeptCd]);
    if(!ret) {
        return false;
    }
    if(ica_closeYm.getValue().length != 6){
        await $c.win.alert("마감년월은(는) 6자리수만큼 입력하십시오.");
        ica_closeYm.focus();
        return;
    }
    ret = await $c.date.isDate(ica_closeYm.getValue()+"01");
    if(!ret) {
        await $c.win.alert("올바른 마감년월을(를) 입력하십시오.");
        ica_closeYm.focus();
        return;
    }

    if (ds_test.getRowCount() > 0) {
        dma_search1.set("finalCloseYm", ds_test.getCellData(0, 'col1'));
    }else {
        dma_search1.set("finalCloseYm", "");        
    }

    // if (ed_acctDeptCd.getValue() == '00000') {
    //     dma_search.set("acctDeptCd", "");
    //     //sbm_retrieve1.setAction = "/ac.fi.fixedaset.cmd.RetrieveFixedAssetComparisonCMD.do";
    //     $c.sbm.execute(sbm_retrieve1);
    //     ed_acctDeptCd.setValue = '00000';
    // } else {
    //     sbm_retrieve1.setAction = "/ac.fi.fixedaset.cmd.RetrieveFixedAssetComparisonCMD.do";
    //     $c.sbm.execute(sbm_retrieve1);
    // }

    if (ed_acctDeptCd.getValue() == '00000') {
        dma_search1.set("acctDeptCd", "");
        dma_search1.set("acctDeptNm", "");
    }else {
        dma_search1.set("acctDeptCd", ed_acctDeptCd.getValue());
        dma_search1.set("acctDeptNm", ed_acctDeptNm.getValue());
    }

    scwin.setInit();
    $c.sbm.execute(sbm_retrieve1);

    // ds_fixedAssetList2.clearData();
    // ds_fixedAssetList3.clearData();

    // ds_search2.setCellData(1, "acctDeptCd", ds_fixedAssetList1.getCellData(1, "acctDeptCd"));
    // ds_search2.setCellData(1, "asetPatternCd", ds_fixedAssetList1.getCellData(1, "asetPatternCd"));
    // ds_search2.setCellData(1, "code", lc_code.getValue());

    // ds_search3.setCellData(1, "acctDeptCd", ds_fixedAssetList1.getCellData(1, "acctDeptCd"));
    // ds_search3.setCellData(1, "acctCd", ds_fixedAssetList1.getCellData(1, "acctCd"));
};

scwin.sbm_retrieve1_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_fixedAssetList1.setNoResultMessageVisible(true);
    let rowCnt = ds_fixedAssetList1.getRowCount();
    totalRows1.setValue(rowCnt);

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
           // $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
           $c.gus.cfAlertMsg("부서-계정별 불일치 현황에 조회된 데이터가 없습니다.");

        } else {
            //조회된 결과 정렬(asis:<param name=SortExpr 참조)
            // ds_master.sort("seq", 0);
            gr_fixedAssetList1.setFocusedCell(0, 0);
            let acctDeptCd    = ds_fixedAssetList1.getCellData(0, "acctDeptCd");
            let asetPatternCd = ds_fixedAssetList1.getCellData(0, "asetPatternCd");
            let acctCd        = ds_fixedAssetList1.getCellData(0, "acctCd");
            dma_search2.set("acctDeptCd"   , acctDeptCd);
            dma_search2.set("asetPatternCd", asetPatternCd);
            dma_search2.set("code"         , lc_code.getValue());

            dma_search3.set("acctDeptCd"   , acctDeptCd);
            dma_search3.set("acctCd"       , acctCd);
        }
    }
};

scwin.sbm_retrieve1_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

scwin.btn_search2_onclick = function (e) {
    scwin.f_Retrieve2(true);
};

/**
 * 조회2
 */
scwin.f_Retrieve2 = function(msg) {
    if (ds_fixedAssetList1.getRowCount() < 1) {
        $c.win.alert("'부서-계정별 불일치 현황'이 조회되지 않았습니다." + '<BR>' +
            "'부서-계정별 불일치 현황'을 먼저 조회 하세요.");
        return;
    } else {

        // let ret;
        // ret = await $c.gus.cfValidate([ica_fromDate1, ica_toDate1]);
        // if(!ret) {
        //     return false;
        // }

        scwin.msg2 = msg;
        ds_fixedAssetList2.removeAll();
        totalRows2.setValue("0");
        // sbm_retrieve2.setAction = "/ac.fi.fixedaset.cmd.RetrieveModificationHistoryCMD.do";
        $c.sbm.execute(sbm_retrieve2);
    }
};

scwin.sbm_retrieve2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_fixedAssetList2.setNoResultMessageVisible(true);
    let rowCnt = ds_fixedAssetList2.getRowCount();
    totalRows2.setValue(rowCnt)
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
           // $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
            if(scwin.msg2) {
                $c.gus.cfAlertMsg("자산 변경이력에 조회된 데이터가 없습니다.");
            }

        }
        gr_fixedAssetList2.setFocusedCell(0);
    }
};

scwin.sbm_retrieve2_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

scwin.btn_search3_onclick = function (e) {
    scwin.f_Retrieve3(true);
};

/**
 * 조회3
 */
scwin.f_Retrieve3 = function(msg) {
    if (ds_fixedAssetList1.getRowCount() < 1) {
        $c.win.alert("'부서-계정별 불일치 현황'이 조회되지 않았습니다." + '<BR>' +
            "'부서-계정별 불일치 현황'을 먼저 조회 하세요.");
        return;
    } else {

        // let ret;
        // ret = await $c.gus.cfValidate([ica_fromDate2, ica_toDate2]);
        // if(!ret) {
        //     return false;
        // }
        scwin.msg3 = msg;
        // sbm_retrieve3.setAction = "/ac.fi.fixedaset.cmd.RetrieveStatementCMD.do";
        ds_fixedAssetList3.removeAll();
        totalRows3.setValue("0");
        $c.sbm.execute(sbm_retrieve3);
    }
};

scwin.sbm_retrieve3_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_fixedAssetList3.setNoResultMessageVisible(true);
    let rowCnt = ds_fixedAssetList3.getRowCount();
    totalRows3.setValue(rowCnt)
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (rowCnt == 0) {
            if(scwin.msg3) {
                $c.gus.cfAlertMsg("전표조회(부서+계정)에 조회된 데이터가 없습니다.");
            }

        }
        gr_fixedAssetList3.setFocusedCell(0);
    }
};

scwin.sbm_retrieve3_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 콤보데이터 검증(자산유형)
 * TOBE 사용안함
 */
scwin.f_CheckComboData = function (objCombo, comboTitle) {
    // if (objCombo.Index == -1 && $c.gus.cfIsNull(objCombo.text) == false) {
