/**
 * 귀속부서코드 팝업 callBack
 */
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_acctDeptCd.setValue(ret[0]);        // 귀속부서코드
        ed_acctDeptNm.setValue(ret[1]);        // 귀속부서명
        ed_acctDeptCd.hidVal = ret[0];         // 히든값
    } else {
        ed_acctDeptCd.setValue("");            // 귀속부서코드
        ed_acctDeptNm.setValue("");            // 귀속부서명
        ed_acctDeptCd.hidVal   = "";           // 히든값
    }
};


/**
 * 팝업결과
 * TOBE 사용안함
 */
scwin.f_resultPopEd = function (strCd, strNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCd.setValue(rtnList[0]); // 코드
        strNm.setValue(rtnList[1]); // 명
        strCd.hidVal = rtnList[0];  // 히든값
    } else {
        strCd.setValue("");         // 코드
        strNm.setValue("");         // 명
        strCd.hidVal = "";          // 히든값
    }
};


/**
 * 팝업체크
 * TOBE 사용안함
 */
scwin.f_checkPopEd = function (strCd, strNm, code) {
    if (strCd.getValue().trim() == strCd.hidVal) {
        return;
    }
    strNm.setValue("");
    strCd.hidVal = "";

    if (strCd.getValue().trim() != "") {
        scwin.f_openPopUp(code, 'T');
    }
};


