/**
 * 마감년월 포커스를 잃었을때
 */
scwin.ica_closeYm_onblur = function (e) {
    //올바른 날짜유무 체크
    if($c.date.isDate(ica_closeYm.getValue()+"01" ) ) {
        scwin.f_getFinalCloseYearMonth();

        let closeYm   = ica_closeYm.getValue();
        let lastDD    = $c.date.getLastDateOfMonth(closeYm);
        ica_fromDate1.setValue(closeYm+"01");
        ica_fromDate2.setValue(closeYm+"01");
        ica_toDate1.setValue(closeYm+lastDD);
        ica_toDate2.setValue(closeYm+lastDD);

    }else {
        ica_fromDate1.setValue("");
        ica_fromDate2.setValue("");
        ica_toDate1.setValue("");
        ica_toDate2.setValue("");
    }
};

/**
 * 조회구분
 */
scwin.lc_code_onviewchange = function (info) {
    if(info.newValue == "0") {
        gr_fixedAssetList1.setHeaderValue("column9"        , "당기말</br>감가상각누계액");
        gr_fixedAssetList2.setColumnVisible("thisYyProvAmt", true);
        gr_fixedAssetList2.setColumnVisible("asetIncrAmt"  , false);
        gr_fixedAssetList2.setColumnVisible("asetDecrAmt"  , false);
    }else {
        gr_fixedAssetList1.setHeaderValue("column9"        , "취득금액");
        gr_fixedAssetList2.setColumnVisible("thisYyProvAmt", false);
        gr_fixedAssetList2.setColumnVisible("asetIncrAmt"  , true);
        gr_fixedAssetList2.setColumnVisible("asetDecrAmt"  , true);
    }
};

/*##############################################################
 * UDC 이벤트
 *##############################################################*/
/**
 * 회사코드(조회) 팝업 호출
 */
scwin.udc_comCode_onclickEvent = function (e) {
    if(ed_coCd.hidVal != ed_coCd.getValue()) {
        ed_coNm.setValue("");
    }
    scwin.f_PopUpCompanyInfo('F');
};
scwin.udc_comCode_onviewchangeCodeEvent = function (info) {
    ed_coNm.setValue("");
    if(!$c.gus.cfIsNull(ed_coCd.getValue())) {
		scwin.f_PopUpCompanyInfo('T');
    }
};

/**
 * 귀속코드(조회) 팝업 호출
 */
scwin.udc_acctDeptCd_onclickEvent = function (e) {
    if(ed_acctDeptCd.hidVal != ed_acctDeptCd.getValue()) {
        ed_acctDeptNm.setValue("");
    }
    let close = "F";
    if(!$c.gus.cfIsNull(ed_acctDeptCd.getValue())) {
        close = "T";
    }
    let id = e.target.id;
    if(id.indexOf("btn") > -1) {
        close = "F";
    }
    scwin.f_openPopUp("1", close);
};
scwin.udc_acctDeptCd_onviewchangeCodeEvent = function (info) {
    ed_acctDeptNm.setValue("");
    if(!$c.gus.cfIsNull(ed_acctDeptCd.getValue())) {
        scwin.f_openPopUp("1", "T");
    }
};


/*##############################################################
 * 그리드, 트리뷰, 데이터리스트 이벤트
 *##############################################################*/
/**
 * DataList의 rowPosition이 변경된 경우 발생
 */
scwin.ds_fixedAssetList1_onrowpositionchange = function (info) {
    let rowIndex      = info.newRowIndex;
    let acctDeptCd    = ds_fixedAssetList1.getCellData(rowIndex, "acctDeptCd");
    let asetPatternCd = ds_fixedAssetList1.getCellData(rowIndex, "asetPatternCd");
    let acctCd        = ds_fixedAssetList1.getCellData(rowIndex, "acctCd");

    dma_search2.set("acctDeptCd"   , acctDeptCd);
    dma_search2.set("asetPatternCd", asetPatternCd);
    dma_search2.set("code"         , lc_code.getValue());

    dma_search3.set("acctDeptCd"   , acctDeptCd);
    dma_search3.set("acctCd"       , acctCd);
};

/**
 * 그리드셀 더블클릭 시
 */
scwin.gr_fixedAssetList1_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    let value = ds_fixedAssetList1.getCellData(rowIndex, "acctDeptCd");
    if(!$c.gus.cfIsNull(value)) {
        scwin.f_Retrieve2(false);
        scwin.f_Retrieve3(false);
    }
};

 /**
  * 그리드 셀 클릭 이벤트
  */
scwin.gr_fixedAssetList3_oncellclick = async function (rowIndex, columnIndex, columnId) {
    //전표팝업조회
    if(columnId == "slipNo") {
        let slipNo = ds_fixedAssetList3.getCellData(rowIndex, "slipNo");
        if(!$c.gus.cfIsNull(slipNo)) {
            await $c.gus.cfShowSlipInfo(slipNo);
        } 
    }
};
